import React, { useEffect, useState } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { supabase } from '../../services/supabaseClient';
import { Lock, CreditCard } from 'lucide-react';

export const SubscriptionGuard = ({ children }: { children: React.ReactNode }) => {
  const { orgId, loading: authLoading } = useAuth();
  const [loading, setLoading] = useState(true);
  const [status, setStatus] = useState<any>(null);

  useEffect(() => {
    if (orgId) checkSubscription();
  }, [orgId]);

  const checkSubscription = async () => {
    // CORRECCIÓN AQUÍ: 
    // Esta línea le asegura a TypeScript que si pasamos de aquí, orgId tiene valor.
    if (!orgId) return; 

    try {
      const { data, error } = await supabase
        .from('organizations')
        .select('plan, status, trial_ends_at, next_payment_date')
        .eq('id', orgId) // Ahora TypeScript sabe que orgId es 'string' seguro
        .single();

      if (error) throw error;
      setStatus(data);
    } catch (e) {
      console.error("Error verificando suscripción", e);
    } finally {
      setLoading(false);
    }
  };

  // Mientras carga la autenticación o la validación de suscripción
  if (authLoading || (loading && orgId)) {
    return <div className="h-screen bg-stone-50 flex items-center justify-center text-stone-500 font-bold animate-pulse">Verificando acceso...</div>;
  }

  // Si no cargó el estado (ej. error de red) o no hay orgId, dejamos pasar o mostramos loading
  if (!status) return <>{children}</>; 

  const now = new Date();
  const trialEnd = new Date(status.trial_ends_at);
  const paymentDue = status.next_payment_date ? new Date(status.next_payment_date) : null;

  // Lógica de Bloqueo
  let isLocked = false;
  let message = "";

  // Caso 1: Prueba Gratuita Vencida
  if (status.plan === 'free_trial' && now > trialEnd) {
    isLocked = true;
    message = "Tu periodo de prueba de 14 días ha finalizado.";
  }

  // Caso 2: Suscripción Vencida (Impago)
  if (status.status === 'past_due' || (status.status === 'active' && paymentDue && now > paymentDue)) {
    isLocked = true;
    message = "Tu suscripción ha vencido. Realiza el pago para continuar.";
  }

  // Si está bloqueado, mostramos pantalla de pago (Paywall)
  if (isLocked) {
    return (
      <div className="h-screen w-full bg-stone-900 flex items-center justify-center p-4">
        <div className="bg-white max-w-md w-full rounded-3xl p-8 text-center shadow-2xl animate-in fade-in zoom-in-95">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-6 text-red-600 shadow-sm">
            <Lock size={32}/>
          </div>
          <h1 className="text-2xl font-bold text-stone-800 mb-2">Acceso Restringido</h1>
          <p className="text-stone-500 mb-8 leading-relaxed">{message}</p>
          
          <div className="bg-stone-50 p-4 rounded-xl border border-stone-200 text-left mb-6 shadow-inner">
            <h3 className="font-bold text-stone-800 flex items-center gap-2 mb-2 text-sm">
              <CreditCard size={16} className="text-emerald-600"/> Cómo reactivar:
            </h3>
            <p className="text-xs text-stone-600 mb-3">Realiza una transferencia o pago QR a la cuenta corporativa y envía el comprobante.</p>
            <div className="font-mono text-xs bg-white p-3 border border-stone-200 rounded-lg text-center text-stone-600">
              <p>Cuenta BNB: <span className="font-bold text-stone-800">123-456789</span></p>
              <p>NIT: <span className="font-bold text-stone-800">1020304050</span></p>
            </div>
          </div>

          <a 
            href="https://wa.me/591XXXXXXXX?text=Hola,%20quiero%20reactivar%20mi%20cuenta%20TraceBlend" 
            target="_blank" 
            rel="noreferrer"
            className="block w-full bg-stone-900 hover:bg-black text-white font-bold py-3.5 rounded-xl transition-all shadow-lg hover:shadow-xl transform hover:-translate-y-0.5"
          >
            Contactar Soporte para Pagar
          </a>
        </div>
      </div>
    );
  }

  // Acceso concedido
  return <>{children}</>;
};

import React, { useEffect, useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getDashboardMetrics, DashboardData } from '../services/dashboardService';
import { StockAlerts } from '../components/StockAlerts';
import { TopProductsRanking } from '../components/TopProductsRanking';
import {
  TrendingUp, TrendingDown, DollarSign, ShoppingBag,
  Activity, Calendar, ClipboardList
} from 'lucide-react';
import { MetricCard } from '../components/ui';
import { useNavigate } from 'react-router-dom';

export function Dashboard() {
  const { user, profile, orgId } = useAuth();
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (orgId) {
      getDashboardMetrics(orgId)
        .then(setData)
        .finally(() => setLoading(false));
    }
  }, [orgId]);

  if (loading) return <div className="p-8 text-stone-400 animate-pulse">Cargando tablero de control...</div>;
  if (!data) return <div className="p-8">Sin datos disponibles.</div>;

  // Calculamos salud financiera
  const balance = data.ventasMes - data.gastosMes;
  const esPositivo = balance >= 0;

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-8">

      {/* 1. BIENVENIDA Y RESUMEN RÁPIDO */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h1 className="text-3xl font-bold text-stone-800">
            Hola, {profile?.first_name || 'Admin'} 👋
          </h1>
          <p className="text-stone-500 mt-1">Aquí tienes el pulso de tu tostaduría hoy.</p>
        </div>
        <div className="bg-white px-4 py-2 rounded-full border border-stone-200 shadow-sm flex items-center gap-2 text-sm font-bold text-stone-600">
          <Calendar size={16} className="text-emerald-600" />
          {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
        </div>
      </div>

      {/* 2. TARJETAS KPI (FINANCIERAS) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">

        {/* Ventas Hoy */}
        <div className="bg-stone-900 text-white p-6 rounded-2xl shadow-xl relative overflow-hidden group">
          <div className="absolute right-[-20px] top-[-20px] opacity-10 group-hover:opacity-20 transition-opacity">
            <DollarSign size={100} />
          </div>
          <p className="text-stone-400 text-xs font-bold uppercase tracking-wider mb-1">Ventas Hoy</p>
          <h3 className="text-3xl font-mono font-bold">Bs {data.ventasHoy.toLocaleString()}</h3>
          <div className="mt-4 flex items-center gap-2 text-xs text-emerald-400 bg-emerald-400/10 w-fit px-2 py-1 rounded-lg">
            <ShoppingBag size={12} /> {data.transaccionesHoy} transacciones
          </div>
        </div>

        {/* Balance Mes */}
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm relative overflow-hidden">
          <p className="text-stone-500 text-xs font-bold uppercase tracking-wider mb-1">Balance Mensual</p>
          <h3 className={`text-3xl font-mono font-bold ${esPositivo ? 'text-emerald-600' : 'text-red-500'}`}>
            {esPositivo ? '+' : ''}Bs {balance.toLocaleString()}
          </h3>
          <p className="text-xs text-stone-400 mt-2 flex items-center gap-1">
            {esPositivo ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
            Ingresos vs Gastos
          </p>
        </div>

        {/* Ticket Promedio */}
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
          <p className="text-stone-500 text-xs font-bold uppercase tracking-wider mb-1">Ticket Promedio</p>
          <h3 className="text-3xl font-mono font-bold text-stone-800">Bs {data.ticketPromedio.toFixed(1)}</h3>
          <p className="text-xs text-stone-400 mt-2">Promedio por cliente hoy</p>
        </div>

        {/* Gastos Mes */}
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
          <p className="text-stone-500 text-xs font-bold uppercase tracking-wider mb-1">Gastos Ejecutados</p>
          <h3 className="text-3xl font-mono font-bold text-red-500">- Bs {data.gastosMes.toLocaleString()}</h3>
          <p className="text-xs text-stone-400 mt-2">Salidas registradas este mes</p>
        </div>
      </div>

      {/* 3. SECCIÓN MIXTA (META + ALERTAS) */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Columna Izquierda: Meta Diaria Visual */}
        <div className="lg:col-span-2 bg-gradient-to-br from-emerald-50 to-white p-6 rounded-3xl border border-emerald-100 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <div>
              <h3 className="font-bold text-xl text-stone-800 flex items-center gap-2">
                <Activity className="text-emerald-600" /> Cobertura Diaria
              </h3>
              <p className="text-sm text-stone-500">Progreso para cubrir costos operativos del día.</p>
            </div>
            <span className="text-3xl font-bold text-emerald-700">{data.progresoMeta.toFixed(0)}%</span>
          </div>

          {/* Barra de Progreso Custom */}
          <div className="h-6 w-full bg-stone-200 rounded-full overflow-hidden shadow-inner relative">
            <div
              className="h-full bg-gradient-to-r from-emerald-500 to-emerald-400 transition-all duration-1000 ease-out flex items-center justify-end pr-2"
              style={{ width: `${data.progresoMeta}%` }}
            >
              {data.progresoMeta > 20 && <span className="text-[10px] font-bold text-white shadow-sm">META</span>}
            </div>
            {/* Marca del 100% */}
            <div className="absolute top-0 bottom-0 left-[100%] w-0.5 bg-stone-400 z-10 border-l border-dashed"></div>
          </div>

          <div className="mt-4 grid grid-cols-3 gap-4 text-center">
            <div className="p-3 bg-white rounded-xl shadow-sm border border-emerald-50">
              <p className="text-[10px] uppercase font-bold text-stone-400">Estado</p>
              <p className="font-bold text-emerald-700">{data.progresoMeta >= 100 ? 'Ganancia 🚀' : 'Cubriendo ⏳'}</p>
            </div>
            {/* Puedes agregar más métricas derivadas aquí */}
          </div>
        </div>

        {/* Columna Derecha: Alertas de Stock con Componente Mejorado */}
        <StockAlerts />

      </div>

      {/* 4. TOP PRODUCTOS MÁS VENDIDOS */}
      <TopProductsRanking days={30} limit={10} />

      {/* 5. ACCESOS RÁPIDOS ADMINISTRATIVOS */}
      {profile?.role === 'administrador' && (
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
          <h3 className="font-bold text-lg text-stone-800 mb-4">Accesos Rápidos</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <button
              onClick={() => window.location.href = '/cierres-historico'}
              className="p-4 bg-gradient-to-br from-emerald-50 to-white rounded-xl border border-emerald-200 hover:border-emerald-400 transition-all hover:shadow-md group"
            >
              <div className="flex items-center gap-3">
                <div className="p-2 bg-emerald-100 rounded-lg group-hover:bg-emerald-200 transition-colors">
                  <ClipboardList size={24} className="text-emerald-700" />
                </div>
                <div className="text-left">
                  <p className="font-bold text-stone-800 group-hover:text-emerald-700 transition-colors">Cierres de Caja</p>
                  <p className="text-xs text-stone-500">Historial y reportes</p>
                </div>
              </div>
            </button>
          </div>
        </div>
      )}

    </div>
  );
}

import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { toast } from 'sonner';
import { supabase } from '../services/supabaseClient';
import { Coffee, Lock, Mail, ArrowRight, Loader2 } from 'lucide-react';
import { LoginSchema, LoginFormData } from '../utils/validationSchemas';

export function Login() {
  const navigate = useNavigate();

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting }
  } = useForm<LoginFormData>({
    resolver: zodResolver(LoginSchema)
  });

  const onSubmit = async (data: LoginFormData) => {
    try {
      const { error } = await supabase.auth.signInWithPassword({
        email: data.email,
        password: data.password
      });

      if (error) throw error;
      navigate('/');
    } catch (error: any) {
      toast.error('Error de acceso', { description: error.message || 'Credenciales incorrectas' });
    }
  };

  return (
    <div className="min-h-screen bg-stone-900 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
        <div className="bg-emerald-900 p-8 text-center">
          <div className="w-16 h-16 bg-emerald-800 rounded-xl flex items-center justify-center mx-auto mb-4 shadow-lg">
            <Coffee size={32} className="text-emerald-100" />
          </div>
          <h1 className="text-2xl font-bold text-white">Trace Blend</h1>
          <p className="text-emerald-200 text-sm">Sistema de Gestión de Tostaduría</p>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="p-8 space-y-6">
          <div className="space-y-4">
            {/* Campo Email */}
            <div>
              <div className="relative">
                <Mail className="absolute left-3 top-3 text-stone-400" size={18} />
                <input
                  type="email"
                  placeholder="Correo electrónico"
                  autoComplete="email"
                  className={`w-full pl-10 p-3 border rounded-xl outline-none transition-colors ${errors.email ? 'border-red-500 focus:border-red-500' : 'focus:border-emerald-500'
                    }`}
                  {...register('email')}
                />
              </div>
              {errors.email && (
                <p className="text-red-500 text-xs mt-1 ml-1">{errors.email.message}</p>
              )}
            </div>

            {/* Campo Password */}
            <div>
              <div className="relative">
                <Lock className="absolute left-3 top-3 text-stone-400" size={18} />
                <input
                  type="password"
                  placeholder="Contraseña"
                  autoComplete="current-password"
                  className={`w-full pl-10 p-3 border rounded-xl outline-none transition-colors ${errors.password ? 'border-red-500 focus:border-red-500' : 'focus:border-emerald-500'
                    }`}
                  {...register('password')}
                />
              </div>
              {errors.password && (
                <p className="text-red-500 text-xs mt-1 ml-1">{errors.password.message}</p>
              )}
            </div>
          </div>

          <div className="flex justify-end">
            <Link to="/recuperar" className="text-xs font-bold text-stone-500 hover:text-emerald-600">
              ¿Olvidaste tu contraseña?
            </Link>
          </div>

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full bg-stone-900 text-white py-3 rounded-xl font-bold flex justify-center items-center gap-2 hover:bg-black transition-all disabled:opacity-70 disabled:cursor-not-allowed"
          >
            {isSubmitting ? <Loader2 className="animate-spin" /> : <>Ingresar <ArrowRight size={18} /></>}
          </button>

          <div className="text-center pt-4 border-t border-stone-100">
            <p className="text-sm text-stone-500">
              ¿Aún no tienes cuenta? <Link to="/registro" className="font-bold text-emerald-600 hover:underline">Regístrate gratis</Link>
            </p>
          </div>
        </form>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { supabase } from '../services/supabaseClient';
import { toast } from 'sonner';
import { Building2, Save, Upload, Coffee } from 'lucide-react';

export function Onboarding() {
  const { orgId, profile } = useAuth();
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    address: '',
    phone: '',
    currency_symbol: 'Bs',
    logo_file: null as File | null
  });

  const handleSave = async () => {
    if (!form.address || !form.phone) return toast.warning("Por favor completa los campos");
    if (!orgId) return;
    setLoading(true);

    try {
      let logoUrl = null;

      // 1. Subir Logo (si el usuario seleccionó uno)
      if (form.logo_file && orgId) {
        const fileExt = form.logo_file.name.split('.').pop();
        const fileName = `${orgId}-logo.${fileExt}`;
        
        const { error: uploadError } = await supabase.storage
          .from('logos')
          .upload(fileName, form.logo_file, { upsert: true });

        if (uploadError) throw uploadError;
        
        const { data: urlData } = supabase.storage.from('logos').getPublicUrl(fileName);
        logoUrl = urlData.publicUrl;
      }

      // 2. Actualizar Organización y Marcar como COMPLETADO
      const { error } = await supabase
        .from('organizations')
        .update({
          address: form.address,
          phone: form.phone,
          currency_symbol: form.currency_symbol,
          logo_url: logoUrl,
          
          setup_completed: true // <--- LA LLAVE QUE ABRE EL SISTEMA
        })
        .eq('id', orgId);

      if (error) throw error;

      toast.success("¡Todo listo! Bienvenido a TraceBlend.");
      // Recarga completa para refrescar el estado del Guardia y el Sidebar
      window.location.href = "/"; 

    } catch (e) {
      console.error(e);
      toast.error("Error al guardar la configuración");
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-xl overflow-hidden flex flex-col md:flex-row">
        
        <div className="bg-stone-900 w-full md:w-1/3 p-8 text-white flex flex-col justify-between">
          <div>
            <div className="w-12 h-12 bg-emerald-600 rounded-xl flex items-center justify-center mb-6">
              <Coffee size={24}/>
            </div>
            <h1 className="text-xl font-bold">Bienvenido, {profile?.first_name}</h1>
            <p className="text-stone-400 text-sm mt-2">Configura los datos básicos de tu tostaduría para comenzar.</p>
          </div>
          <div className="flex gap-2">
            <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
            <div className="w-2 h-2 rounded-full bg-stone-700"></div>
          </div>
        </div>

        <div className="p-8 flex-1 space-y-5">
           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Moneda</label>
             <div className="flex gap-2 mt-2">
                {['Bs', '$us', '€'].map(sym => (
                  <button key={sym} onClick={() => setForm({...form, currency_symbol: sym})}
                    className={`px-3 py-2 rounded-lg border text-sm font-bold ${form.currency_symbol === sym ? 'bg-stone-800 text-white' : 'hover:bg-stone-50'}`}>
                    {sym}
                  </button>
                ))}
             </div>
           </div>

           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Dirección</label>
             <input className="w-full p-3 border rounded-xl mt-1 bg-stone-50" 
               placeholder="Ej: Av. Principal #123"
               value={form.address} onChange={e => setForm({...form, address: e.target.value})} />
           </div>

           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Teléfono</label>
             <input className="w-full p-3 border rounded-xl mt-1 bg-stone-50" 
               placeholder="+591 ..."
               value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} />
           </div>

           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Logo</label>
             <div className="border-2 border-dashed border-stone-200 rounded-xl p-4 mt-1 text-center cursor-pointer hover:border-emerald-500 relative">
               <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer"
                 onChange={e => setForm({...form, logo_file: e.target.files?.[0] || null})} />
               {form.logo_file ? <span className="text-emerald-600 font-bold">{form.logo_file.name}</span> : <span className="text-stone-400 text-xs">Subir imagen...</span>}
             </div>
           </div>

           <button onClick={handleSave} disabled={loading}
             className="w-full bg-emerald-600 text-white py-3 rounded-xl font-bold hover:bg-emerald-700 flex justify-center items-center gap-2 mt-2">
             {loading ? 'Guardando...' : <>Guardar y Entrar <Save size={18}/></>}
           </button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Package, Search, Plus, Edit2, Tag, Coffee, Box, Utensils,
  Save, X, DollarSign, Barcode, List, Trash2
} from 'lucide-react';
import { useAuth } from '../hooks/useAuth';
import { toast } from 'sonner';
import {
  getTodosLosProductos, crearProducto, actualizarProducto,
  getInsumosDisponibles, getRecetaProducto,
  ProductoForm, IngredienteReceta
} from '../services/productosService';
import { EmptyState, Button } from '../components/ui';

// Categorías Visuales
const CAT_ICONS: Record<string, any> = {
  'Café': Coffee, 'Grano': Package, 'Pastelería': Utensils, 'Accesorios': Box, 'General': Tag
};

export function Productos() {
  const { orgId } = useAuth();
  const [loading, setLoading] = useState(true);
  const [productos, setProductos] = useState<any[]>([]);
  const [insumos, setInsumos] = useState<any[]>([]); // Lista de insumos disponibles

  const [filtro, setFiltro] = useState('');
  const [catFiltro, setCatFiltro] = useState('Todas');
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Formulario Principal
  const [formData, setFormData] = useState<ProductoForm>({
    name: '', sku: '', sale_price: '', category: 'General',
    is_roasted: false, package_weight_grams: '', stock_inicial: '',
    receta: []
  });

  // Estado temporal para agregar ingrediente
  const [newIngrediente, setNewIngrediente] = useState<{ id: string, qty: string }>({ id: '', qty: '' });

  useEffect(() => {
    if (orgId) {
      cargar();
      getInsumosDisponibles(orgId).then(setInsumos);
    }
  }, [orgId]);

  const cargar = async () => {
    setLoading(true);
    try {
      const data = await getTodosLosProductos(orgId!);
      setProductos(data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const handleSave = async () => {
    if (!formData.name || !formData.sale_price) return toast.warning("Nombre y Precio requeridos");
    try {
      if (isEditing && selectedId) {
        await actualizarProducto(selectedId, formData, orgId!);
        toast.success("Producto actualizado");
      } else {
        await crearProducto(formData, orgId!);
        toast.success("Producto creado");
      }
      setShowModal(false);
      resetForm();
      cargar();
    } catch (e: any) { toast.error(e.message); }
  };

  const openEdit = async (p: any) => {
    // Cargar receta existente
    let recetaActual: IngredienteReceta[] = [];
    try {
      recetaActual = await getRecetaProducto(p.id);
    } catch (e) { console.error("Error cargando receta", e); }

    setFormData({
      name: p.name,
      sku: p.sku || '',
      sale_price: p.sale_price,
      category: p.category || 'General',
      is_roasted: p.is_roasted,
      package_weight_grams: p.package_weight_grams || '',
      stock_inicial: '',
      receta: recetaActual
    });
    setSelectedId(p.id);
    setIsEditing(true);
    setShowModal(true);
  };

  const resetForm = () => {
    setFormData({
      name: '', sku: '', sale_price: '', category: 'General',
      is_roasted: false, package_weight_grams: '', stock_inicial: '', receta: []
    });
    setNewIngrediente({ id: '', qty: '' });
    setIsEditing(false);
    setSelectedId(null);
  };

  // --- Helpers de Receta ---
  const agregarIngrediente = () => {
    if (!newIngrediente.id || !newIngrediente.qty) return;
    const insumoReal = insumos.find(i => i.id === newIngrediente.id);
    if (!insumoReal) return;

    const item: IngredienteReceta = {
      supply_id: newIngrediente.id,
      quantity: Number(newIngrediente.qty),
      nombre_insumo: insumoReal.name,
      unidad: insumoReal.unit_measure
    };

    setFormData({ ...formData, receta: [...(formData.receta || []), item] });
    setNewIngrediente({ id: '', qty: '' });
  };

  const quitarIngrediente = (index: number) => {
    const nuevaReceta = [...(formData.receta || [])];
    nuevaReceta.splice(index, 1);
    setFormData({ ...formData, receta: nuevaReceta });
  };

  // Filtrado
  const filtrados = productos.filter(p => {
    const matchText = p.name.toLowerCase().includes(filtro.toLowerCase()) || p.sku?.toLowerCase().includes(filtro.toLowerCase());
    const matchCat = catFiltro === 'Todas' || p.category === catFiltro;
    return matchText && matchCat;
  });
  const categoriasUnicas = ['Todas', ...new Set(productos.map(p => p.category || 'General'))];

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] bg-stone-50 overflow-hidden">

      {/* HEADER */}
      <div className="bg-white border-b border-stone-200 px-6 py-4 flex justify-between items-center gap-4 shadow-sm">
        <div>
          <h1 className="text-2xl font-bold text-stone-800 flex items-center gap-2">
            <Package className="text-emerald-600" /> Catálogo Maestro
          </h1>
          <p className="text-xs text-stone-500">Define productos y sus fichas técnicas.</p>
        </div>
        <button onClick={() => { resetForm(); setShowModal(true); }} className="bg-stone-900 text-white px-4 py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg hover:bg-black transition-all">
          <Plus size={20} /> Nuevo
        </button>
      </div>

      {/* FILTROS */}
      <div className="px-6 py-2 bg-stone-50 border-b border-stone-200 flex gap-2 overflow-x-auto no-scrollbar items-center">
        <div className="relative w-64 mr-4">
          <Search className="absolute left-3 top-2.5 text-stone-400" size={16} />
          <input className="w-full pl-9 p-2 border rounded-lg bg-white text-sm" placeholder="Buscar..." value={filtro} onChange={e => setFiltro(e.target.value)} />
        </div>
        {categoriasUnicas.map(cat => (
          <button key={cat} onClick={() => setCatFiltro(cat)} className={`px-3 py-1 rounded-full text-xs font-bold whitespace-nowrap border ${catFiltro === cat ? 'bg-stone-800 text-white border-stone-800' : 'bg-white text-stone-500 border-stone-200'}`}>
            {cat}
          </button>
        ))}
      </div>

      {/* GRID PRODUCTOS */}
      <div className="flex-1 overflow-y-auto p-6">
        {filtrados.length === 0 ? (
          <EmptyState
            icon={Package}
            title="No hay productos registrados"
            description={
              filtro
                ? `No se encontraron productos que coincidan con "${filtro}". Intenta con otro término.`
                : catFiltro !== 'Todas'
                  ? `No hay productos en la categoría "${catFiltro}". Prueba con otra categoría.`
                  : 'Comienza creando tu primer producto para empezar a vender.'
            }
            actionLabel="Crear Producto"
            onAction={() => { resetForm(); setShowModal(true); }}
            secondaryActionLabel={catFiltro !== 'Todas' || filtro ? 'Limpiar Filtros' : undefined}
            onSecondaryAction={catFiltro !== 'Todas' || filtro ? () => { setCatFiltro('Todas'); setFiltro(''); } : undefined}
          />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {filtrados.map(p => {
              const Icon = CAT_ICONS[p.category] || Tag;
              return (
                <div key={p.id} className="bg-white p-4 rounded-xl border border-stone-200 shadow-sm hover:shadow-md transition-smooth group relative flex flex-col justify-between animate-fade-in">
                  <div>
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex items-center gap-3">
                        <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${p.is_roasted ? 'bg-amber-50 text-amber-700' : 'bg-stone-100 text-stone-600'}`}>
                          <Icon size={20} />
                        </div>
                        <div>
                          <h3 className="font-bold text-stone-800 leading-tight">{p.name}</h3>
                          <span className="text-[10px] text-stone-400 uppercase font-bold tracking-wider">{p.category}</span>
                        </div>
                      </div>
                    </div>
                    {p.sku && <p className="text-xs text-stone-400 font-mono flex items-center gap-1 mb-2"><Barcode size={10} /> {p.sku}</p>}
                  </div>

                  <div className="pt-3 border-t border-stone-100 flex justify-between items-end">
                    <button onClick={() => openEdit(p)} className="text-stone-400 hover:text-emerald-600 font-bold text-xs flex items-center gap-1 transition-smooth">
                      <Edit2 size={12} /> Editar
                    </button>
                    <p className="text-xl font-bold text-stone-800">Bs {p.sale_price}</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* MODAL */}
      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b border-stone-100 flex justify-between items-center bg-stone-50">
              <h3 className="font-bold text-lg text-stone-800">{isEditing ? 'Editar Producto' : 'Nuevo Producto'}</h3>
              <button onClick={() => setShowModal(false)} className="p-1 rounded-full hover:bg-stone-200"><X size={20} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">

              {/* DATOS BÁSICOS */}
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-xs font-bold text-stone-400 uppercase">Nombre</label>
                  <input className="w-full p-2 border rounded-lg mt-1" placeholder="Ej: Cappuccino" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-400 uppercase">Categoría</label>
                  <select className="w-full p-2 border rounded-lg mt-1 bg-white" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option value="General">General</option>
                    <option value="Café">Bebidas Café</option>
                    <option value="Grano">Grano / Bolsas</option>
                    <option value="Pastelería">Pastelería</option>
                    <option value="Accesorios">Accesorios</option>
                  </select>
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-400 uppercase">Precio (Bs)</label>
                  <div className="relative mt-1">
                    <DollarSign size={14} className="absolute left-2 top-3 text-stone-400" />
                    <input type="number" className="w-full pl-6 p-2 border rounded-lg font-bold" value={formData.sale_price} onChange={e => setFormData({ ...formData, sale_price: e.target.value })} />
                  </div>
                </div>
              </div>

              {/* SECCIÓN FICHA TÉCNICA (RECETA) */}
              {!formData.is_roasted && (
                <div className="bg-stone-50 p-4 rounded-xl border border-stone-200">
                  <h4 className="font-bold text-stone-700 mb-3 flex items-center gap-2">
                    <List size={16} className="text-emerald-600" /> Ficha Técnica (Receta)
                  </h4>
                  <p className="text-xs text-stone-500 mb-4">Define qué insumos se descuentan al vender este producto.</p>

                  {/* Agregar Item */}
                  <div className="flex gap-2 mb-4">
                    <select className="flex-1 p-2 border rounded-lg text-sm" value={newIngrediente.id} onChange={e => setNewIngrediente({ ...newIngrediente, id: e.target.value })}>
                      <option value="">+ Agregar Insumo...</option>
                      {insumos.map(i => <option key={i.id} value={i.id}>{i.name} ({i.unit_measure})</option>)}
                    </select>
                    <input
                      type="number"
                      className="w-20 p-2 border rounded-lg text-sm"
                      placeholder="Cant."
                      value={newIngrediente.qty}
                      onChange={e => setNewIngrediente({ ...newIngrediente, qty: e.target.value })}
                    />
                    <button onClick={agregarIngrediente} className="bg-stone-800 text-white px-3 rounded-lg font-bold hover:bg-black">+</button>
                  </div>

                  {/* Lista Items */}
                  {formData.receta && formData.receta.length > 0 ? (
                    <div className="space-y-2">
                      {formData.receta.map((r, idx) => (
                        <div key={idx} className="flex justify-between items-center bg-white p-2 rounded border border-stone-200 text-sm">
                          <span>{r.nombre_insumo}</span>
                          <div className="flex items-center gap-3">
                            <span className="font-mono font-bold text-stone-600">{r.quantity} {r.unidad}</span>
                            <button onClick={() => quitarIngrediente(idx)} className="text-red-400 hover:text-red-600"><Trash2 size={14} /></button>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="text-center py-4 text-xs text-stone-400 italic border-2 border-dashed border-stone-200 rounded-lg">
                      No hay ingredientes definidos.
                    </div>
                  )}
                </div>
              )}

              {/* CHECKBOX CAFÉ TOSTADO */}
              <div className="pt-2 border-t border-stone-100">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" className="accent-emerald-600" checked={formData.is_roasted} onChange={e => setFormData({ ...formData, is_roasted: e.target.checked })} />
                  <span className="text-sm font-bold text-stone-600">Es Café Tostado (Bolsa para venta)</span>
                </label>
                {formData.is_roasted && (
                  <div className="mt-2 ml-6">
                    <label className="text-xs font-bold text-stone-400 uppercase">Peso Neto (Gramos)</label>
                    <input type="number" className="block w-32 p-2 border rounded-lg mt-1" value={formData.package_weight_grams} onChange={e => setFormData({ ...formData, package_weight_grams: e.target.value })} />
                  </div>
                )}
              </div>

            </div>

            <div className="p-4 bg-stone-50 border-t border-stone-100 flex gap-3">
              <button onClick={() => setShowModal(false)} className="flex-1 py-3 text-stone-500 font-bold hover:bg-stone-200 rounded-xl transition-colors">Cancelar</button>
              <button onClick={handleSave} className="flex-1 py-3 bg-stone-900 text-white rounded-xl font-bold shadow-lg hover:bg-black transition-colors flex justify-center gap-2">
                <Save size={18} /> Guardar Producto
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getPromociones, crearPromocion, toggleEstadoPromocion, eliminarPromocion, Promocion } from '../services/promocionesService';
import { getTodosLosProductos as getProductos } from '../services/productosService'; 
import { toast } from 'sonner';
import { Plus, Trash2, Tag, Power, X, Gift, Percent, Users, Calendar } from 'lucide-react';

export function Promociones() {
  const { orgId } = useAuth();
  const [promociones, setPromociones] = useState<Promocion[]>([]);
  const [productos, setProductos] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);

  // Formulario y Tipo de Promoción
  const [tipoPromo, setTipoPromo] = useState<'producto' | 'convenio'>('producto');
  const [form, setForm] = useState({
    name: '',
    product_id: '' as string | null,
    discount_percent: 0,
    is_courtesy: false,
    start_date: new Date().toISOString().slice(0, 16), // Formato para input datetime-local
    end_date: ''
  });

  useEffect(() => {
    if (orgId) cargarDatos();
  }, [orgId]);

  const cargarDatos = async () => {
    if (!orgId) return;
    setLoading(true);
    try {
      const [promos, prods] = await Promise.all([
        getPromociones(), 
        getProductos(orgId)
      ]);
      setPromociones(promos);
      setProductos(prods);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const handleGuardar = async () => {
    if (!form.name || !form.start_date || !form.end_date) return toast.warning("Datos incompletos");
    if (tipoPromo === 'producto' && !form.product_id) return toast.warning("Selecciona un producto");

    try {
      await crearPromocion({
        name: form.name,
        // Lógica clave: Si es convenio, product_id es null
        product_id: tipoPromo === 'producto' ? form.product_id : null,
        discount_percent: form.discount_percent,
        is_courtesy: form.is_courtesy,
        start_date: form.start_date,
        end_date: form.end_date,
        is_active: true
      }, orgId!);
      
      toast.success(tipoPromo === 'convenio' ? "Convenio Global Creado" : "Oferta de Producto Creada");
      setShowModal(false);
      
      // Reset del formulario
      setForm({ 
        name: '', 
        product_id: '', 
        discount_percent: 0, 
        is_courtesy: false, 
        start_date: new Date().toISOString().slice(0, 16), 
        end_date: '' 
      });
      cargarDatos();
    } catch (e: any) { toast.error(e.message); }
  };

  const handleToggle = async (p: Promocion) => {
    try { await toggleEstadoPromocion(p.id, p.is_active); cargarDatos(); } catch (e) { toast.error("Error"); }
  };

  const handleEliminar = async (id: string) => {
    if (!confirm("¿Eliminar?")) return;
    try { await eliminarPromocion(id); cargarDatos(); } catch (e) { toast.error("Error"); }
  };

  return (
    <div className="p-6 bg-stone-50 min-h-screen">
      
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-2xl font-bold text-stone-800">Promociones y Convenios</h1>
          <p className="text-stone-500">Gestiona ofertas automáticas y descuentos globales.</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-stone-900 text-white px-4 py-2 rounded-xl font-bold flex items-center gap-2 hover:bg-black transition-all shadow-lg shadow-stone-200">
          <Plus size={20}/> Nuevo
        </button>
      </div>

      {/* Grid de Promociones */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {promociones.map(p => (
          <div key={p.id} className={`bg-white p-5 rounded-2xl border relative transition-all ${p.is_active ? 'border-stone-200 shadow-sm hover:shadow-md' : 'border-stone-100 opacity-60 grayscale'}`}>
            
            {/* Badge Tipo */}
            <div className={`absolute top-0 right-0 px-3 py-1 rounded-bl-xl text-[10px] font-bold uppercase tracking-wider ${p.product_id ? 'bg-blue-50 text-blue-600' : 'bg-purple-50 text-purple-600'}`}>
                {p.product_id ? 'Producto' : 'Convenio Global'}
            </div>

            <div className="flex justify-between items-start mb-4 mt-2">
              <div className="flex items-center gap-3">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${p.product_id ? 'bg-blue-100 text-blue-600' : 'bg-purple-100 text-purple-600'}`}>
                   {p.product_id ? <Tag size={24}/> : <Users size={24}/>}
                </div>
                <div>
                  <h3 className="font-bold text-stone-800 leading-tight text-lg">{p.name}</h3>
                  <p className="text-xs text-stone-500 mt-0.5">{p.products?.name || 'Aplica a toda la cuenta'}</p>
                </div>
              </div>
            </div>

            <div className="bg-stone-50 p-3 rounded-xl text-sm space-y-2 mb-4 border border-stone-100">
               <div className="flex justify-between items-center">
                 <span className="text-stone-500">Beneficio:</span> 
                 <span className={`font-bold px-2 py-0.5 rounded ${p.is_courtesy ? 'bg-emerald-100 text-emerald-700' : 'bg-stone-200 text-stone-800'}`}>
                    {p.is_courtesy ? '100% GRATIS' : `-${p.discount_percent}% OFF`}
                 </span>
               </div>
               <div className="flex justify-between items-center">
                 <span className="text-stone-500 flex items-center gap-1"><Calendar size={12}/> Vence:</span> 
                 <span className="font-medium text-stone-700">{new Date(p.end_date).toLocaleDateString()}</span>
               </div>
            </div>

            <div className="flex justify-end gap-2 pt-2 border-t border-stone-100">
               <button onClick={() => handleToggle(p)} className={`p-2 rounded-lg transition-colors ${p.is_active ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-400 hover:text-stone-600 hover:bg-stone-100'}`} title={p.is_active ? "Desactivar" : "Activar"}>
                 <Power size={20}/>
               </button>
               <button onClick={() => handleEliminar(p.id)} className="p-2 text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Eliminar">
                 <Trash2 size={20}/>
               </button>
            </div>
          </div>
        ))}
        
        {promociones.length === 0 && !loading && (
            <div className="col-span-full py-12 text-center text-stone-400 border-2 border-dashed border-stone-200 rounded-2xl">
                <Tag size={40} className="mx-auto mb-2 opacity-20"/>
                <p>No hay promociones registradas</p>
            </div>
        )}
      </div>

      {/* MODAL CREAR */}
      {showModal && (
        <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in-95">
            <div className="p-5 border-b border-stone-100 flex justify-between items-center bg-stone-50">
                <h3 className="font-bold text-lg text-stone-800">Nueva Promoción</h3>
                <button onClick={() => setShowModal(false)} className="p-1 hover:bg-stone-200 rounded-full transition-colors"><X size={20} className="text-stone-400"/></button>
            </div>
            
            <div className="p-6 space-y-5">
              {/* Switch Tipo */}
              <div className="flex bg-stone-100 p-1 rounded-xl">
                  <button onClick={() => setTipoPromo('producto')} className={`flex-1 py-2.5 text-sm font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${tipoPromo==='producto' ? 'bg-white shadow text-stone-800' : 'text-stone-400 hover:text-stone-600'}`}>
                    <Tag size={16}/> Oferta Producto
                  </button>
                  <button onClick={() => setTipoPromo('convenio')} className={`flex-1 py-2.5 text-sm font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${tipoPromo==='convenio' ? 'bg-white shadow text-purple-700' : 'text-stone-400 hover:text-stone-600'}`}>
                    <Users size={16}/> Convenio Global
                  </button>
              </div>

              <div>
                <label className="text-xs font-bold text-stone-500 uppercase ml-1">Nombre</label>
                <input className="w-full p-3 border border-stone-200 rounded-xl mt-1 focus:ring-2 focus:ring-stone-800 outline-none transition-all" 
                  placeholder={tipoPromo==='convenio' ? "Ej: Convenio Librería, Club de Lectura..." : "Ej: Happy Hour, 2x1..."} 
                  value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
              </div>

              {tipoPromo === 'producto' && (
                <div>
                    <label className="text-xs font-bold text-stone-500 uppercase ml-1">Producto</label>
                    <select className="w-full p-3 border border-stone-200 rounded-xl mt-1 bg-white outline-none" 
                      value={form.product_id || ''} onChange={e => setForm({...form, product_id: e.target.value})}>
                      <option value="">Seleccionar producto...</option>
                      {productos.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="text-xs font-bold text-stone-500 uppercase ml-1">Beneficio</label>
                    <div className="flex gap-2 mt-1">
                        <button onClick={() => setForm({...form, is_courtesy: false})} className={`flex-1 py-3 rounded-xl border font-bold text-sm transition-all ${!form.is_courtesy ? 'border-stone-800 bg-stone-50 text-stone-800' : 'border-stone-200 text-stone-400'}`}>
                            % Off
                        </button>
                        <button onClick={() => setForm({...form, is_courtesy: true, discount_percent: 100})} className={`flex-1 py-3 rounded-xl border font-bold text-sm transition-all ${form.is_courtesy ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-stone-200 text-stone-400'}`}>
                            Gratis
                        </button>
                    </div>
                 </div>
                 {!form.is_courtesy && (
                   <div>
                      <label className="text-xs font-bold text-stone-500 uppercase ml-1">Porcentaje</label>
                      <div className="relative mt-1">
                        <input type="number" className="w-full p-3 border border-stone-200 rounded-xl outline-none text-center font-bold text-lg" placeholder="20"
                            value={form.discount_percent} onChange={e => setForm({...form, discount_percent: Number(e.target.value)})} />
                        <span className="absolute right-4 top-4 text-stone-400 font-bold">%</span>
                      </div>
                   </div>
                 )}
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="text-xs font-bold text-stone-500 uppercase ml-1">Desde</label>
                   <input type="datetime-local" className="w-full p-3 border border-stone-200 rounded-xl mt-1 text-sm bg-white"
                     value={form.start_date} onChange={e => setForm({...form, start_date: e.target.value})} />
                </div>
                <div>
                   <label className="text-xs font-bold text-stone-500 uppercase ml-1">Hasta</label>
                   <input type="datetime-local" className="w-full p-3 border border-stone-200 rounded-xl mt-1 text-sm bg-white"
                     value={form.end_date} onChange={e => setForm({...form, end_date: e.target.value})} />
                </div>
              </div>

              <button onClick={handleGuardar} className="w-full bg-stone-900 text-white py-4 rounded-xl font-bold hover:bg-black transition-all shadow-xl shadow-stone-200 mt-2 flex justify-center items-center gap-2">
                Guardar Promoción
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
